const form = $('📝 Formulaire1').first().json;
const inputData = $input.first().json;

let topic = form.sujet || 'Immobilier Sénégal';
if (inputData.choices && inputData.choices.length > 0) {
  topic = inputData.choices[0].message.content.replace(/["']/g, '').trim();
}

const wordTarget = (form.longueur||'').includes('800') ? 800 : (form.longueur||'').includes('2000') ? 2000 : 1200;
return [{ json: {
  topic,
  category: form.categorie || 'Actualité',
  angle: form.angle || '',
  audience: form.public_cible || '',
  wordTarget,
  email: form.email_notif || '',
  query1: topic + ' Sénégal immobilier 2024 2025',
  query2: topic + ' loi OHADA réglementation juridique Sénégal',
  query3: topic + ' investissement Dakar statistiques prix marché',
  sessionId: Date.now().toString()
}}];

const allResults = $input.all().flatMap(item => item.json.results || []);
const seen = new Set();
const unique = allResults.filter(r => { if (!r.url || seen.has(r.url)) return false; seen.add(r.url); return true; });
const authoritative = ['worldbank.org','bceao.int','apix.sn','ohada.com','un.org','afdb.org'];
const scored = unique.map(r => {
  let s = 50;
  if (authoritative.some(d => (r.url||'').includes(d))) s += 30;
  if (/\d+[\s]*(\%|FCFA|XOF|milliard|million)/i.test(r.content||r.snippet||'')) s += 15;
  const age = (Date.now() - new Date(r.published_date||Date.now()).getTime()) / (30*24*3600*1000);
  if (age > 24) s -= 60; else if (age < 6) s += 20; else if (age < 12) s += 10;
  s += ((r.score||0)*10);
  return {...r, _score: Math.round(s), _age: Math.round(age)};
});
const valid = scored.filter(s => s._age <= 24).sort((a,b) => b._score - a._score).slice(0,8);
const cfg = $('⚙️ Config1').first().json;
return [{ json: {
  ...cfg,
  sourcesForPrompt: valid.map(s => ({
    title: s.title||'Sans titre',
    url: s.url||'',
    author: s.author||'Non précisé',
    date: s.published_date||'Date inconnue',
    excerpt: (s.content||s.raw_content||s.snippet||'').slice(0,600)
  })),
  validSourceCount: valid.length,
  hasMinimumSources: valid.length >= 2
}}];

const d = $input.first().json;
const sources = d.sourcesForPrompt || [];
const sourcesText = sources.map((s, i) => `[Source ${i+1}] ${s.title}\nURL: ${s.url}\nExtrait: ${s.excerpt}`).join('\n\n');

const systemPrompt = `Tu es un journaliste d'investigation senior spécialisé dans l'immobilier africain, notamment sénégalais. Tu rédiges pour Dousel Immo des analyses de fond qui prennent position claire, argumentent avec des données et challengent les idées reçues. Tes articles défendent une thèse — ils ne listent pas des informations.

PHILOSOPHIE RÉDACTIONNELLE :
- Chaque H2 = un ARGUMENT formulé comme une assertion affirmée (pas juste un sujet)
  Mauvais : \"Le marché immobilier à Dakar\"
  Bon : \"Pourquoi le marché dakarois est structurellement biaisé contre les locataires\"
- Chaque chiffre ancré à sa source inline : [Titre source](url)
- Chaque section développe : thèse → preuves chiffrées → analyse → implication
- Le lecteur repart avec une conviction, pas juste des informations

STRUCTURE OBLIGATOIRE (${d.wordTarget || 1200} mots) :

1. INTRODUCTION (150-200 mots) :
   - Accroche forte : chiffre choc, contradiction, ou question provocatrice
   - Contextualisation + annonce de la thèse centrale

2. CORPS : 3 à 5 sections argumentatives (200-300 mots chacune) :
   - H2 formulé comme un argument affirmé
   - Paragraphes avec citations [texte source](url) dans le fil
   - H3 pour sous-points si nécessaire

3. BLOCS DE RICHESSE OBLIGATOIRES :
   a) 1 tableau comparatif (type table) : données chiffrées par zone/type/période
   b) 1 citation d'expert (type quote) avec auteur réel issu des sources
   c) 2 encadrés minimum (type callout) avec items sourcés
   d) 1 liste ordonnée (type list, ordered:true) : étapes ou recommandations

4. CONCLUSION (100-150 mots) + CTA vers /biens

TYPES DE BLOCS DISPONIBLES :
{\"type\":\"paragraph\",\"text\":\"Texte avec [lien source](url) intégré naturellement\"}
{\"type\":\"heading\",\"level\":2,\"text\":\"H2 = argument affirmé\"}
{\"type\":\"heading\",\"level\":3,\"text\":\"H3 précision\"}
{\"type\":\"quote\",\"text\":\"Citation marquante\",\"author\":\"Prénom Nom, Titre\"}
{\"type\":\"callout\",\"title\":\"📌 Ce que révèlent ces chiffres\",\"items\":[\"Fait 1 [source](url)\",\"Fait 2 chiffré\",\"Implication pratique\"]}
{\"type\":\"table\",\"headers\":[\"Critère\",\"Valeur A\",\"Valeur B\"],\"rows\":[[\"Ligne\",\"v1\",\"v2\"]]}
{\"type\":\"list\",\"ordered\":true,\"items\":[\"1. Action concrète\",\"2. Action concrète\",\"3. Action concrète\"]}
{\"type\":\"cta\",\"text\":\"Consulter les offres\",\"href\":\"/biens\",\"style\":\"primary\"}

PUBLIC CIBLE : ${d.audience || 'Grand public immobilier'}
ANGLE : ${d.angle || 'Analyse critique'}

FORMAT DE RÉPONSE (JSON valide uniquement, aucun texte autour) :
{
  \"title\": \"Titre journalistique qui annonce une position (60-70 car.)\",
  \"excerpt\": \"Chapeau 150-160 car résumant la thèse centrale\",
  \"meta_title\": \"Titre SEO 55-60 car\",
  \"meta_description\": \"Description SEO 150-160 car\",
  \"author_name\": \"Équipe éditoriale Dousel\",
  \"read_time_estimate\": 6,
  \"confidence_score\": 72,
  \"sources_used\": [{\"title\": \"...\", \"url\": \"...\"}],
  \"blocks\": [
    MINIMUM 15 BLOCS : 1 table + 1 quote + 2 callouts + 1 list ordonnée
  ]
}`;

const userPrompt = `Rédige un article de fond argumentatif sur ce sujet pour Dousel Immo :

Sujet : ${d.topic}
Catégorie : ${d.category}
Angle éditorial : ${d.angle}
Public cible : ${d.audience}
Longueur cible : ${d.wordTarget} mots

SOURCES DISPONIBLES (analyse, croise et cite) :
${sourcesText}

CHECKLIST :
✓ L'article défend-il une thèse claire et affirmée ?
✓ Chaque H2 est-il un argument (pas juste un sujet) ?
✓ Y a-t-il au moins 15 blocs ?
✓ Y a-t-il 1 tableau, 1 citation, 2 callouts, 1 liste ordonnée ?
✓ Les sources sont-elles citées avec [texte](url) dans les paragraphes ?

Réponds UNIQUEMENT avec le JSON valide.`;

return [{ json: {
  ...d,
  _llmPayload: {
    model: 'anthropic/claude-3.5-sonnet',
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: userPrompt }
    ],
    temperature: 0.8,
    max_tokens: 8000
  }
}}];

const inputData = $input.first().json;
const cfg = $('📝 Build Prompt1').first().json;

let rawContent = '';
try {
  rawContent = inputData.choices[0].message.content;
} catch(e) {
  rawContent = JSON.stringify(inputData);
}

let article = {};
try {
  const jsonMatch = rawContent.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    article = JSON.parse(jsonMatch[0]);
  }
} catch(e) {
  article = { title: 'Article généré', excerpt: '', blocks: [], tags: [], sources: [], seo: {} };
}

const slug = (article.slug || article.title || 'article-' + Date.now())
  .toLowerCase()
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-+|-+$/g, '');

const supabasePayload = {
  title: article.title || '',
  slug: slug,
  excerpt: article.excerpt || '',
  category: cfg.category || article.category || 'Actualité',
  tags: article.tags || [],
  blocks: article.blocks || [],
  sources: article.sources || [],
  cover_image: null,
  status: 'draft',
  created_at: new Date().toISOString(),
  word_count: cfg.wordTarget || 1200
};

return [{ json: {
  supabasePayload,
  sourcesUsed: cfg.sourcesForPrompt || [],
  confidenceScore: 50,
  email: cfg.email || '',
  _config: cfg
}}];

const parserOutput = $('🔧 Parser Réponse1').first().json;
const article = parserOutput.supabasePayload || {};
const topic = (article.title || '').toLowerCase();

const keywords = [
  topic.split(' ').filter(w => w.length > 4).slice(0, 2).join(' '),
  'immobilier Sénégal',
  'Dakar'
].filter(Boolean);

const pexelsQuery = keywords[0] || 'immobilier Dakar Senegal';

return [{ json: {
  pexelsQuery: pexelsQuery,
  _parserData: parserOutput
}}];

var parserOutput = $('🔧 Parser Réponse1').first().json;
var article = parserOutput.supabasePayload || {};
var config   = parserOutput._config || {};
var photos = $input.first().json.photos || [];
var coverUrl = photos.length > 0 && photos[0].src ? (photos[0].src.large2x || photos[0].src.large) : null;
var galleryItems = photos.slice(1, 4).map(function(p) {
  return { cloudinaryId: p.src ? (p.src.large || p.src.medium) : '', alt: p.alt || '', caption: p.photographer ? ('Crédit : ' + p.photographer) : '' };
});
var finalBlocks = (article.blocks || []).slice();
if (galleryItems.length > 0) {
  finalBlocks.splice(Math.min(3, finalBlocks.length), 0, { id: 'gallery-pexels-' + Date.now(), type: 'gallery', images: galleryItems });
}
var supabasePayload = Object.assign({}, article, { cover_image: coverUrl, blocks: finalBlocks });
return [{ json: { supabasePayload: supabasePayload, sourcesUsed: parserOutput.sourcesUsed || [], confidenceScore: parserOutput.confidenceScore || 50, email: config.email || '', _config: config } }];

var d=$input.first().json;
var p=d.supabasePayload||{};
var s=d.confidenceScore||50;
var issues=[];
if(!p.title||p.title.length<10){s-=25;issues.push('Titre manquant');}
if(!p.excerpt){s-=10;issues.push('Excerpt manquant');}
if(!p.blocks||p.blocks.length<3){s-=20;issues.push('Contenu insuffisant');}
if(!p.cover_image){s-=5;issues.push('Image manquante');}
s=Math.max(0,Math.min(100,s));
var ok=s>=55&&!!p.title&&(p.blocks||[]).length>=3;
return[{json:Object.assign({},d,{qualityScore:s,qualityApproved:ok,qualityIssues:issues})}];
